def coding_assistant_loop(client, user_request, repo_context, max_turns=5):
    conversation = [{"role": "system", "content": "You are a code debugging assistant."},
                   {"role": "user", "content": user_request}]

    for turn in range(max_turns):
        response = client.chat.completions.create(
            messages=conversation + repo_context,
            tools=client.tools
        )

        # Tool execution
        if response.tool_calls:
            tool_results = execute_tools(response.tool_calls)
            conversation.append({"role": "assistant", "content": response.content})
            conversation.append({"role": "tool", "content": tool_results})
        else:
            break

    return response.content

def get_repo_context(client, query: str, top_k: int = 5) -> list:
    relevant_files = client.memory_bank.search(
        query=query,
        namespace="repo_files",
        limit=top_k,
        filter={"extension": ["py", "js", "ts"]}
    )

    context_docs = []
    for doc in relevant_files:
        content = client.memory_bank.retrieve(doc['id'])
        context_docs.append({
            "role": "context",
            "content": f"File: {doc['metadata']['path']}\n{content}",
            "metadata": doc['metadata']
        })

    return context_docs

