from vex import verify, Guardrail

@pip install vex-sdk

def safe_agent_response(client_response):
    guards = [
        Guardrail("code_correctness", checks=["syntax", "imports_valid", "test_passing"]),
        Guardrail("security_vuln", patterns=["eval(", "exec(", "__import__("]),
        Guardrail("credential_leak", regex=[r'api[_-]?key[:=]\s*["\'][a-zA-Z0-9]{32,}["\']']),
        Guardrail("dependency_safety", pypi_check=True),
        Guardrail("license_compliance", allowed=["MIT", "Apache-2.0", "BSD-3"])
    ]

    verified = verify(client_response.content, guards=guards)
    if verified.passed:
        return verified.output
    else:
        return f"Blocked: {verified.issues}"

def secure_coding_loop(client, request, repo_context):
    response = coding_assistant_loop(client, request, repo_context)

    # Vex verification
    verified_code = safe_agent_response(response)
    if not verified_code.startswith("Blocked:"):
        sandbox_result = sandbox_exec(verified_code)
        sandbox_verified = verify_sandbox_output(sandbox_result)

        if sandbox_verified['safe']:
            return {
                'status': 'success',
                'code': verified_code,
                'tests': sandbox_verified['coverage'],
                'output': sandbox_verified['output']
            }

    return {'status': 'failed_verification', 'issues': verified_code}
